import React from "react";
import { NavLink, useNavigate } from "react-router-dom";

function Navbar() {
  const navigate = useNavigate();

  // Styling for active and normal links
  const linkStyle = {
    margin: "0 15px",
    textDecoration: "none",
    color: "#333",
    fontWeight: "500",
  };

  const activeStyle = {
    color: "#FF385C", // Airbnb red
    borderBottom: "2px solid #FF385C",
    paddingBottom: "3px",
  };

  return (
    <nav
      style={{
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center",
        padding: "15px 40px",
        background: "white",
        boxShadow: "0 2px 5px rgba(0,0,0,0.1)",
        position: "sticky",
        top: 0,
        zIndex: 1000,
      }}
    >
      {/* Logo */}
      <h2
        onClick={() => navigate("/")}
        style={{
          fontSize: "22px",
          fontWeight: "bold",
          color: "#FF385C",
          cursor: "pointer",
        }}
      >
        Airbnb Clone
      </h2>

      {/* Navigation Links */}
      <div>
        <NavLink
          to="/"
          style={({ isActive }) => (isActive ? { ...linkStyle, ...activeStyle } : linkStyle)}
        >
          Home
        </NavLink>
        <NavLink
          to="/experiences"
          style={({ isActive }) => (isActive ? { ...linkStyle, ...activeStyle } : linkStyle)}
        >
          Experiences
        </NavLink>
        <NavLink
          to="/services"
          style={({ isActive }) => (isActive ? { ...linkStyle, ...activeStyle } : linkStyle)}
        >
          Services
        </NavLink>
      </div>

      {/* Auth Buttons */}
      <div>
        <button
          onClick={() => navigate("/login")}
          style={{
            background: "transparent",
            border: "1px solid #FF385C",
            color: "#FF385C",
            padding: "6px 14px",
            borderRadius: "20px",
            marginRight: "8px",
            cursor: "pointer",
          }}
        >
          Login
        </button>
        <button
          onClick={() => navigate("/signup")}
          style={{
            background: "#FF385C",
            border: "none",
            color: "white",
            padding: "6px 14px",
            borderRadius: "20px",
            cursor: "pointer",
          }}
        >
          Sign Up
        </button>
      </div>
    </nav>
  );
}

export default Navbar;
